"use strict";const navToggler=document.querySelector(".nav__toggler"),navList=document.querySelector(".nav__list"),nav=document.querySelector(".nav"),header=document.querySelector(".header"),main=document.querySelector(".main");navToggler.addEventListener("click",(()=>{const t=navList.getBoundingClientRect().height,e=header.getBoundingClientRect().height;nav.classList.contains("nav-active")?(nav.classList.remove("nav-active"),main.style.transform="",navList.style.transform="translateY(-100%)",barsIcon.style.display="block",timesIcon.style.display="none"):(nav.classList.add("nav-active"),main.style.transform=`translateY(${t-e}px)`,navList.style.transform="translateY(0)",barsIcon.style.display="none",timesIcon.style.display="block")})),window.addEventListener("resize",(()=>{if(window.matchMedia("(max-width: 600px)").matches,nav.classList.contains("nav-active")){const t=navList.getBoundingClientRect().height,e=header.getBoundingClientRect().height;main.style.transform=`translateY(${t-e}px)`}})),main.addEventListener("transitionend",(function(){nav.classList.contains("nav-active")||(this.style.transform="")})),window.addEventListener("DOMContentLoaded",(t=>{const e=document.querySelectorAll(".projects__tile"),n=["--slideInLeft","--slideInRight","--slideInTop","--slideInBottom"];e.forEach((t=>{let e=Math.floor(Math.random()*n.length),a=n[e];t.classList.add("projects__tile"+a)}))}));